import './App.css';
import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
    const [listOfUsers, setListOfUsers] = useState([]);

    useEffect(() => {
        axios.get("http://localhost:3001/users").then((response) => {
            setListOfUsers(response.data);
        })
    }, []);
    return (
        <div className="App">
            {listOfUsers.map((value, key) => {
                return (
                    <div class="mt-6 border-t border-white/10">
                        <dl class="divide-y divide-white/10">
                            <div className="text-sm/6 font-medium text-gray-100">User</div>
                            <div className="mt-1 text-sm/6 text-gray-400 sm:col-span-2 sm:mt-0">{value.username}</div>
                            <div className="text-sm/6 font-medium text-gray-100">Email</div>
                            <div className="mt-1 text-sm/6 text-gray-400 sm:col-span-2 sm:mt-0">{value.email}</div>
                        </dl>
                    </div>
                );
            })}
        </div>
    );
}

export default App;
